require_once __DIR__.'/../../config/auth.php';require_once __DIR__.'/../../config/database.php';require_once __DIR__.'/../../config/helper.php';require_admin();$pdo=db();$rows=[];if($pdo){$rows=$pdo->query('SELECT q.*,COUNT(s.id) total_soal FROM quiz q LEFT JOIN soal s ON s.quiz_id=q.id GROUP BY q.id ORDER BY q.id DESC')->fetchAll();}$adminPageTitle='Kelola Kuis';$adminPageDescription='Kelola paket kuis dan jumlah soal untuk siswa.';$adminActive='quiz';include __DIR__.'/../../includes/admin_header.php';
