<section class="admin-card"><div class="admin-toolbar"><div><h2 style="margin:0">Paket Kuis</h2><p class="muted" style="margin:4px 0 0">Daftar kuis pada database.</p></div><a class="btn" href="<?=url('admin/quiz/tambah.php')?>">+ Tambah Kuis</a></div><?php if($rows):?><div class="admin-table-wrap"><table><thead><tr><th>Judul</th><th>Kategori</th><th>Kelas</th><th>Soal</th><th>Status</th><th>Aksi</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['judul'])?></strong></td><td><?=e($r['kategori'])?></td><td><?=e($r['kelas']?:'-')?></td><td><?= (int)$r['total_soal'] ?></td><td><span class="status-badge <?=e($r['status'])?>"><?=e(ucfirst($r['status']))?></span></td><td><div class="table-actions"><a href="<?=url('admin/quiz/edit.php?id='.$r['id'])?>">Edit</a><form class="inline-form" method="post" action="<?=url('admin/quiz/hapus.php')?>" onsubmit="return confirm('Hapus kuis dan seluruh soalnya?')"><?=csrf_field()?><input type="hidden" name="id" value="<?=$r['id']?>"><button class="danger">Hapus</button></form></div></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="admin-empty"><span>❓</span><strong>Belum ada kuis</strong><small>Tambahkan paket kuis baru.</small></div><?php endif;?></section><?php include __DIR__.'/../../includes/admin_footer.php'; ?>
